// BAD - runs every frame for every instance
void AMyActor::Tick(float DeltaTime) {
    TArray<AActor*> Actors;
    UGameplayStatics::GetAllActorsOfClass(this, AEnemy::StaticClass(), Actors);
}

// GOOD - runs on a timer every 0.5s
AMyActor::AMyActor() {
    PrimaryActorTick.bCanEverTick = false;  // disable tick
}
void AMyActor::BeginPlay() {
    Super::BeginPlay();
    GetWorldTimerManager().SetTimer(QueryTimer, this, &AMyActor::UpdateEnemyList, 0.5f, true);
}

// BAD - hard reference forces loading at construction
UPROPERTY(EditDefaultsOnly)
UTexture2D* HugeTexture;  // always in memory

// GOOD - soft reference, load on demand
UPROPERTY(EditDefaultsOnly)
TSoftObjectPtr<UTexture2D> HugeTexture;

// Load when needed
if (!HugeTexture.IsValid()) {
    HugeTexture.LoadSynchronous();
}
